describe('useCurrentUser', () => {
  beforeEach(() => {
    vi.clearAllMocks();
    mockOnChange.mockReturnValue(() => {});
  });

  it('returns null when not authenticated', () => {
    pb.authStore.record = null;

    const { result } = renderHook(() => useCurrentUser());
    expect(result.current).toBeNull();
  });

  it('reflects the initial auth record', () => {
    pb.authStore.record = makeUser();

    const { result } = renderHook(() => useCurrentUser());
    expect(result.current?.id).toBe('u1');
  });

  it('updates when authStore fires onChange', () => {
    pb.authStore.record = null;

    let storedCallback: ((token: string, record: unknown) => void) | null = null;
    mockOnChange.mockImplementation((cb: (token: string, record: unknown) => void) => {
      storedCallback = cb;
      return () => {};
    });

    const { result } = renderHook(() => useCurrentUser());
    expect(result.current).toBeNull();

    act(() => {
      storedCallback?.('tok', makeUser({ id: 'u2' }));
    });

    expect(result.current?.id).toBe('u2');
  });
});

describe('useRole', () => {
  beforeEach(() => {
    vi.clearAllMocks();
    mockOnChange.mockReturnValue(() => {});
  });

  it('returns all false with isLoading false when not authenticated', async () => {
    pb.authStore.record = null;
    mockGetList.mockResolvedValue({ totalItems: 0, items: [] });

    const { result } = renderHook(() => useRole());
    await act(async () => {});

    expect(result.current.isAdmin).toBe(false);
    expect(result.current.isProjectManager).toBe(false);
    expect(result.current.isResourceManager).toBe(false);
    expect(result.current.isLoading).toBe(false);
  });

  it('sets isAdmin and isProjectManager from user fields', async () => {
    pb.authStore.record = makeUser({ is_admin: true, is_project_manager: true });
    mockGetList.mockResolvedValue({ totalItems: 0, items: [] });

    const { result } = renderHook(() => useRole());
    await act(async () => {});

    expect(result.current.isAdmin).toBe(true);
    expect(result.current.isProjectManager).toBe(true);
  });

  it('sets isResourceManager when user has direct reports', async () => {
    pb.authStore.record = makeUser();
    mockGetList.mockResolvedValue({ totalItems: 2, items: [] });

    const { result } = renderHook(() => useRole());
    await act(async () => {});

    expect(result.current.isResourceManager).toBe(true);
    expect(result.current.isLoading).toBe(false);
  });

  it('handles PB query failure gracefully', async () => {
    pb.authStore.record = makeUser();
    mockGetList.mockRejectedValue(new Error('network error'));

    const { result } = renderHook(() => useRole());
