'use client';

import { useState, useEffect } from 'react';
import { pb } from './pb';

interface FeatureFlagRecord {
  name: string;
  enabled: boolean;
  /** Empty array means all departments; non-empty is an allowlist. */
  enabled_departments: string[];
}

export const RESOURCE_PLANNING_V1 = 'resource-planning-v1' as const;

/**
 * Checks if a named feature flag is enabled for the given department.
 * Returns false on any error (e.g. collection not yet migrated, flag not found).
 */
export async function checkFeatureFlag(
  flagName: string,
  department?: string,
): Promise<boolean> {
  try {
    const record = await pb
      .collection('feature_flags')
      .getFirstListItem<FeatureFlagRecord>(`name = "${flagName}"`);

    if (!record.enabled) return false;

    const depts = record.enabled_departments ?? [];
    if (depts.length === 0) return true;
    return department != null && depts.includes(department);
  } catch {
    return false;
  }
}

export function useFeatureFlag(
  flagName: string,
  department?: string,
): { enabled: boolean; isLoading: boolean } {
  const [enabled, setEnabled] = useState(false);
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    checkFeatureFlag(flagName, department)
      .then(setEnabled)
      .finally(() => setIsLoading(false));
  }, [flagName, department]);

  return { enabled, isLoading };
}

