'use client';

import { useEffect } from 'react';
import Link from 'next/link';
import { useRouter } from 'next/navigation';
import { pb } from '../lib/pb';
import { useCurrentUser, useRole } from '../lib/roles';
import { useFeatureFlag, RESOURCE_PLANNING_V1 } from '../lib/featureFlags';

/**
 * Wraps a component so it redirects unauthenticated users to /login.
 * Use for page-level route protection in the App Router.
 */
export function withAuth<P extends object>(Component: React.ComponentType<P>) {
  function AuthGuard(props: P) {
    const user = useCurrentUser();
    const router = useRouter();

    useEffect(() => {
      if (user === null) {
        router.replace('/login');
      }
    }, [user, router]);

    if (!user) return null;
    return <Component {...props} />;
  }

  AuthGuard.displayName = `withAuth(${Component.displayName ?? Component.name ?? 'Component'})`;
  return AuthGuard;
}

interface NavShellProps {
  children: React.ReactNode;
}

/**
 * Application shell with sidebar navigation.
 * Redirects unauthenticated users to /login.
