'use client';

import { useEffect, useState } from 'react';
import { useRouter } from 'next/navigation';
import { NavShell } from '../../../components/NavShell';
import { SkillTable } from '../../../components/SkillTable';
import { pb } from '../../../lib/pb';
import { useRole } from '../../../lib/roles';
import { useFeatureFlag, RESOURCE_PLANNING_V1 } from '../../../lib/featureFlags';
import type { Skill } from '../../../lib/types';

export default function RmSkillsPage() {
  const roles = useRole();
  const featureFlag = useFeatureFlag(RESOURCE_PLANNING_V1);
  const router = useRouter();
  const [skills, setSkills] = useState<Skill[]>([]);
  const [loading, setLoading] = useState(true);
  const [fetchError, setFetchError] = useState<string | null>(null);

  useEffect(() => {
    if (!roles.isLoading && !roles.isResourceManager && !roles.isAdmin) {
      router.replace('/');
    }
  }, [roles.isLoading, roles.isResourceManager, roles.isAdmin, router]);

  useEffect(() => {
    if (!featureFlag.isLoading && !featureFlag.enabled) {
      router.replace('/');
    }
  }, [featureFlag.isLoading, featureFlag.enabled, router]);

  useEffect(() => {
    pb.collection('skills')
      .getFullList<Skill>({ sort: 'name' })
      .then(setSkills)
      .catch(e =>
        setFetchError(e instanceof Error ? e.message : 'Failed to load skills'),
      )
      .finally(() => setLoading(false));
  }, []);

  return (
    <NavShell>
      <div className="mx-auto max-w-4xl">
        <div className="mb-6">
          <h1 className="text-2xl font-bold text-zinc-900">Skill Catalog</h1>
          <p className="mt-1 text-sm text-zinc-500">
            Company-wide skill inventory. Deactivating a skill preserves existing
            assignments.
          </p>
        </div>

        {loading || roles.isLoading || featureFlag.isLoading ? (
          <div className="flex items-center justify-center py-16 text-sm text-zinc-400">
            Loading…
          </div>
        ) : fetchError ? (
          <div
            role="alert"
            className="rounded-md border border-red-200 bg-red-50 px-4 py-3 text-sm text-red-700"
          >
            {fetchError}
          </div>
        ) : (
          <SkillTable initialSkills={skills} />
        )}
      </div>
    </NavShell>
  );
}

